import{_ as e,a,b as n,c as o,d as r,e as i,f as l}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as d,o as s,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Thêm Discord Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/discord.md","filePath":"vi-VN/upload/discord.md","lastUpdated":1781962217000}'),p={name:"vi-VN/upload/discord.md"};function g(u,t,b,m,v,k){return s(),c("div",null,[...t[0]||(t[0]=[h('<h1 id="them-discord-channel" tabindex="-1">Thêm Discord Channel <a class="header-anchor" href="#them-discord-channel" aria-label="Permalink to &quot;Thêm Discord Channel&quot;">​</a></h1><h2 id="can-chuan-bi-gi-truoc-khi-bat-đau" tabindex="-1">Cần chuẩn bị gì trước khi bắt đầu <a class="header-anchor" href="#can-chuan-bi-gi-truoc-khi-bat-đau" aria-label="Permalink to &quot;Cần chuẩn bị gì trước khi bắt đầu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Discord account</td><td>Dùng để tạo server, channel và developer application.</td></tr><tr><td>Một Discord server</td><td>Bot phải join server trước khi access channel.</td></tr><tr><td>Một text channel</td><td>Images và files sẽ được gửi vào channel này.</td></tr><tr><td>Discord Developer Portal</td><td>Dùng để tạo application, tạo bot và lấy <code>Bot Token</code>.</td></tr></tbody></table><h2 id="them-o-đau" tabindex="-1">Thêm ở đâu <a class="header-anchor" href="#them-o-đau" aria-label="Permalink to &quot;Thêm ở đâu&quot;">​</a></h2><ol><li>Mở System Settings.</li><li>Vào Upload Settings.</li><li>Nhấn Add Channel ở góc trên bên phải.</li><li>Chọn <code>Discord</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Tác dụng</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết cho channel này, ví dụ &quot;Discord Primary&quot;.</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>ID của target text channel.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Chỉ dùng nếu Discord CDN access không ổn định. Nhập full URL, bao gồm <code>https://</code>.</td><td>Optional</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="_1-tao-discord-server-va-text-channel" tabindex="-1">1. Tạo Discord Server và Text Channel <a class="header-anchor" href="#_1-tao-discord-server-va-text-channel" aria-label="Permalink to &quot;1. Tạo Discord Server và Text Channel&quot;">​</a></h3><ol><li>Mở Discord.</li><li>Tạo server mới, hoặc dùng existing server bạn sở hữu.</li><li>Tạo một text channel trong server đó.</li></ol><p><img src="'+e+'" alt="Create a server" loading="lazy"></p><h3 id="_2-tao-bot-trong-discord-developer-portal" tabindex="-1">2. Tạo Bot trong Discord Developer Portal <a class="header-anchor" href="#_2-tao-bot-trong-discord-developer-portal" aria-label="Permalink to &quot;2. Tạo Bot trong Discord Developer Portal&quot;">​</a></h3><ol><li>Mở Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Nhấn <code>New Application</code>.</li><li>Nhập application name và tạo.</li><li>Mở trang <code>Bot</code> từ left sidebar.</li><li>Generate hoặc reset token trong trang <code>Bot</code>.</li><li>Lưu token.</li></ol><p>Token này chính là <code>Bot Token</code> cần nhập trong ImgBed.</p><p><img src="'+a+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-tao-oauth2-invite-link-va-install-bot" tabindex="-1">3. Tạo OAuth2 Invite Link và Install Bot <a class="header-anchor" href="#_3-tao-oauth2-invite-link-va-install-bot" aria-label="Permalink to &quot;3. Tạo OAuth2 Invite Link và Install Bot&quot;">​</a></h3><ol><li>Mở trang <code>OAuth2</code> từ left sidebar.</li><li>Trong scopes, chọn <code>bot</code>.</li><li>Trong permission area, enable các permissions này:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>Ở cuối page, xác nhận integration type là <code>Guild Install</code>.</li><li>Copy generated URL.</li><li>Mở URL đó trong browser.</li><li>Chọn target server.</li><li>Hoàn tất authorization flow.</li></ol><p><img src="'+n+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+o+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-enable-developer-mode-va-copy-channel-id" tabindex="-1">4. Enable Developer Mode và Copy Channel ID <a class="header-anchor" href="#_4-enable-developer-mode-va-copy-channel-id" aria-label="Permalink to &quot;4. Enable Developer Mode và Copy Channel ID&quot;">​</a></h3><ol><li>Nhấn biểu tượng gear cạnh avatar ở góc dưới bên trái Discord.</li><li>Mở Advanced từ left sidebar.</li><li>Enable Developer Mode.</li><li>Quay lại target text channel.</li><li>Right-click tên channel.</li><li>Nhấn Copy Channel ID.</li></ol><p>Số được copy là <code>Channel ID</code> mà ImgBed cần.</p><p><img src="'+r+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+i+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-đien-discord-channel-trong-imgbed" tabindex="-1">5. Điền Discord Channel trong ImgBed <a class="header-anchor" href="#_5-đien-discord-channel-trong-imgbed" aria-label="Permalink to &quot;5. Điền Discord Channel trong ImgBed&quot;">​</a></h3><p>Quay lại channel configuration dialog và điền như sau:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên channel tùy chọn, ví dụ <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token đã lưu từ trang <code>Bot</code> trong Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID đã copy từ Discord.</td></tr><tr><td>Proxy URL (optional)</td><td>Chỉ nhập nếu cần, ví dụ <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Điền xong thì nhấn Save.</p><p><img src="'+l+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cách kiểm tra</th></tr></thead><tbody><tr><td>Channel card xuất hiện</td><td>Sau khi save, trang Upload Settings cần hiển thị Discord channel card.</td></tr><tr><td>Channel bật được</td><td>Active switch nên giữ trạng thái on.</td></tr><tr><td>Configuration đã lưu</td><td>Detail view cần cho thấy Bot Token và Channel ID đã được lưu.</td></tr><tr><td>Upload hoạt động</td><td>Upload một test image và xác nhận nó xuất hiện trong target Discord text channel.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tạo Discord server</span></span>
<span class="line"><span>-&gt; Tạo text channel</span></span>
<span class="line"><span>-&gt; Tạo bot trong Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Lưu Bot Token từ trang Bot</span></span>
<span class="line"><span>-&gt; Trong OAuth2, chọn bot, View Channels, Send Messages, Attach Files và Read Message History</span></span>
<span class="line"><span>-&gt; Copy generated URL và authorize bot cho target server</span></span>
<span class="line"><span>-&gt; Đảm bảo target text channel có cùng permissions</span></span>
<span class="line"><span>-&gt; Enable Developer Mode</span></span>
<span class="line"><span>-&gt; Right-click target text channel và copy Channel ID</span></span>
<span class="line"><span>-&gt; Nhập Bot Token và Channel ID trong ImgBed</span></span>
<span class="line"><span>-&gt; Save và upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const f=d(p,[["render",g]]);export{C as __pageData,f as default};
